refsection.programlisting:
// Create example file
data = [1 2 3; 4 5 6; 7 8 9];
test_file = TMPDIR + "/test_info.xlsx";
xlsxWrite(data, test_file, "title", "Test File", "subject", "Example", ..
          "description", "Test file for xlsxInfo");

// Get information about the entire workbook
info = xlsxInfo(test_file)

// Get information about a specific sheet by name
sheet_info = xlsxInfo(test_file, "Sheet1")
